    Callback = function(Value)
        M.setTeleporting(Value)
        if Value then
            M.setPlayerIndex(0)
            local target = M.getNextTarget()
            M.setCurrentTarget(target)
            if target then
                M.anchorToPlayer(target)
            end
        else
            M.setCurrentTarget(nil)
        end
    end,
})
MainPlayer:AddToggle("TargetMovingToggle", {
    Text    = "Mục tiêu đang di chuyển",
    Default = true,
    Callback = function(Value)
        M.setTargetMovingPlayers(Value)
        if not Value and not M.getTargetStillPlayers() then
            M.setTargetStillPlayers(true)
        end
    end,
})
MainPlayer:AddToggle("TargetStillToggle", {
    Text    = "Mục tiêu đang đứng yên",
    Default = true,
    Callback = function(Value)
        M.setTargetStillPlayers(Value)
        if not Value and not M.getTargetMovingPlayers() then
            M.setTargetMovingPlayers(true)
        end
    end,
})
MainPlayer:AddSlider("BehindDistance", {
    Text     = "Khoảng cách phía sau",
